def chunk(text, size=400, overlap=50):
    words = text.split()
    step = size - overlap
    return [
        " ".join(words[i:i + size])
        for i in range(0, len(words), step)
    ]

chunks = []
for doc in documents:
    chunks.extend(chunk(doc))

SYSTEM = (
    "Answer using ONLY the context. If it's not there, "
    "say 'I don't know.' Quote the source line."
)

def build_prompt(question, ctx_chunks):
    context = "

---

".join(ctx_chunks)
    return f"{SYSTEM}

Context:
{context}

Question: {question}"
